from jqdata import *

def initialize(context):
    log.set_level('order', 'error')
    set_option('use_real_price', True)
    set_benchmark('000300.XSHG')
    set_order_cost(OrderCost(close_tax=0.001, open_commission=0.000085, close_commission=0.000085, min_commission=5), type='stock')

    g.interval = 10
    g.day_count = 0

    run_daily(trade, '09:35')

def trade(context):
    g.day_count += 1

    if g.day_count % g.interval == 1:
        stocks = select_stocks()
        if stocks:
            rebalance(context, stocks)
            log.info(f"调仓: {len(stocks)}只")

def select_stocks():
    result = []

    # 小市值: 中证1000前25只
    try:
        small = get_index_stocks('000852.XSHG')
        if small:
            result.extend(small[:25])
    except:
        pass

    # 白马: 沪深300中ROE>0的前10只
    try:
        white = get_index_stocks('000300.XSHG')
        if white:
            q = query(indicator.code).filter(
                indicator.code.in_(white),
                indicator.roe > 0
            ).order_by(indicator.roe.desc()).limit(10)
            df = get_fundamentals(q)
            if df is not None:
                result.extend(df['code'].tolist()[:10])
    except:
        pass

    result = list(set(result))
    return result[:25]

def rebalance(ctx, target):
    if not target:
        return

    # 卖出
    for s in list(ctx.portfolio.positions.keys()):
        if s not in target:
            order_target_value(s, 0)

    # 买入
    value = ctx.portfolio.total_value / len(target)
    for s in target:
        order_target_value(s, value)

